#include "kernel_operator.h"

using namespace AscendC;

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00301Custom {
public:
    __aicore__ inline KernelCa6k00301Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, GM_ADDR z,
                                uint32_t batch, uint32_t M, uint32_t N, uint32_t K,
                                uint32_t tileM, uint32_t tileK, uint32_t tileN)
    {
        batch_ = batch;
        M_ = M;
        N_ = N;
        K_ = K;
        tileM_ = tileM;
        tileK_ = tileK;
        tileN_ = tileN;

        xGm_.SetGlobalBuffer((__gm__ float*)x, batch * M * K);
        yGm_.SetGlobalBuffer((__gm__ float*)y, batch * K * N);
        zGm_.SetGlobalBuffer((__gm__ float*)z, batch * M * N);
    }

    __aicore__ inline void Process()
    {
        if (batch_ == 0 || M_ == 0 || N_ == 0 || K_ == 0) return;

        uint32_t blockIdx = GetBlockIdx();
        if (blockIdx >= batch_) return;

        uint32_t b = blockIdx;

        // Create per-batch global tensors using pointer arithmetic (avoid Slice)
        GlobalTensor<float> xBatch;
        xBatch.SetGlobalBuffer(xGm_.GetData() + b * M_ * K_, M_ * K_);
        GlobalTensor<float> yBatch;
        yBatch.SetGlobalBuffer(yGm_.GetData() + b * K_ * N_, K_ * N_);
        GlobalTensor<float> zBatch;
        zBatch.SetGlobalBuffer(zGm_.GetData() + b * M_ * N_, M_ * N_);

        // Use AscendC MatMul (capital M, capital M, three template params)
        MatMul<float, float, float> mm;
        mm.SetTensorA(xBatch, M_, K_, false);
        mm.SetTensorB(yBatch, K_, N_, false);
        mm.SetTensorC(zBatch, M_, N_, false);
        mm.SetConfig(1, false, false, false);
        mm.SetTiling(tileM_, tileK_, tileN_);
        mm.IterateAll();
    }

private:
    GlobalTensor<float> xGm_;
    GlobalTensor<float> yGm_;
    GlobalTensor<float> zGm_;

    uint32_t batch_ {0};
    uint32_t M_ {0};
    uint32_t N_ {0};
    uint32_t K_ {0};
    uint32_t tileM_ {0};
    uint32_t tileK_ {0};
    uint32_t tileN_ {0};
};

extern "C" __global__ __aicore__ void ca6k00301_custom(GM_ADDR x, GM_ADDR y, GM_ADDR z, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00301Custom op;
    op.Init(x, y, z,
            tiling_data.batch, tiling_data.m, tiling_data.n, tiling_data.k,
            tiling_data.tileM, tiling_data.tileK, tiling_data.tileN);
    op.Process();
}
